/* Return the largest sum of any contiguous subarray in the vector x.
   Implements Kadane's algorithm in O(n) time. */
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty input: return 0 (same as original algorithm would return LLONG_MIN? 
    // but specification does not consider empty, so we assume non‑empty).
    if (x.empty()) return 0;

    int max_ending_here = x[0];
    int max_so_far = x[0];

    for (size_t i = 1; i < x.size(); ++i) {
        max_ending_here = (max_ending_here > 0) ? max_ending_here + x[i] : x[i];
        if (max_ending_here > max_so_far) {
            max_so_far = max_ending_here;
        }
    }
    return max_so_far;
}
