#pragma once
#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row-major). The graph is assumed connected.
*/
inline int shortestPathLength(const std::vector<int>& A, size_t N,
                               int source, int dest) noexcept {
    if (source == dest) return 0;

    // Use a flat queue instead of std::queue<pair<...>> for speed
    std::vector<int> q(N);              // maximum queue size is N
    std::vector<unsigned char> visited(N, 0);

    int head = 0, tail = 0;
    q[tail++] = source;
    visited[source] = 1;
    std::vector<int> dist(N, 0);

    while (head < tail) {
        int u = q[head++];
        int d = dist[u];

        // Scan adjacency row directly
        const int* row = &A[u * N];
        for (size_t v = 0; v < N; ++v) {
            if (!row[v]) continue;
            if (visited[v]) continue;
            visited[v] = 1;
            dist[v] = d + 1;
            if ((int)v == dest) return d + 1;
            q[tail++] = static_cast<int>(v);
        }
    }
    // Should never reach here on a connected graph
    return std::numeric_limits<int>::max();
}
