*/
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    const std::size_t n = x.size();
    int64_t result = 0;

    /* The sum of all prefix sums equals
        Σ_{j=0}^{n-1} x[j] * (n-j)
      which can be evaluated in a single pass. */
