/*
 * Compute the reverse prefix sum of the vector `x` into `output`.
 * The result is equivalent to:
 *   reverseX  = std::vector<int>(x.rbegin(), x.rend());
 *   std::inclusive_scan(reverseX.begin(), reverseX.end(), output.begin());
 *
 * This implementation performs the scan in a single backward loop
 * without allocating the intermediate reversed vector, which is
 * faster for all sizes and keeps the memory footprint minimal.
 *
 * The function assumes that `output` has enough space to hold the result;
 * the caller should either resize it beforehand or let the function
 * resize it to `x.size()`.  This implementation resizes it if needed.
 */
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output) {
    const std::size_t n = x.size();
    // Ensure the output vector has the correct size.
    if (output.size() != n)
        output.resize(n);

    if (n == 0) return;

    // Start from the last element: the first element of the result.
    output[n - 1] = x[n - 1];

    // Perform a backward inclusive scan.
    for (std::size_t i = n - 1; i-- > 0; ) {
        output[i] = output[i + 1] + x[i];
    }
}
