/*
 * Apply the isPowerOfTwo function to every value in x and store the results in mask.
 *
 * Example:
 *   input : [8, 0, 9, 7, 15, 64, 3]
 *   output: [true, false, false, false, false, true, false]
 *
 * The function preserves the exact behaviour of the original implementation
 * while exploiting data‑parallelism and eliminating bounds‑check overhead.
 */
void mapPowersOfTwo(const std::vector<int> &x, std::vector<bool> &mask) {
    const std::size_t n = x.size();

    // Ensure mask has the same size; the harness guarantees this, but we keep the
    // check to preserve safety in case of misuse.
    if (mask.size() != n)
        mask.resize(n);

    // Obtain raw pointers for zero‑overhead access.
    const int *restrict in = x.data();
    bool *restrict out = reinterpret_cast<bool*>(mask.data()); // std::vector<bool> uses bit packing

    // Parallelise over the whole range. The static schedule yields excellent
    // load balancing for this simple work‑per‑iteration code.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        out[i] = isPowerOfTwo(in[i]);
    }
