       syntax `reduction(+:array[:N])`.  The compiler generates
       a private copy for each thread and merges them efficiently
       at the end of the loop.  The loop has a simple body and is
       thread‑friendly, so a static schedule gives the best
       performance on 8 cores. */
#pragma omp parallel for schedule(static) reduction(+:bins[:10])
    for (size_t i = 0; i < x.size(); ++i)
    {
        /* Casting to size_t after the division ensures the floor
           is taken as in the original code (values are non‑negative). */
        size_t const bin = static_cast<size_t>(x[i]) / 10;
