#pragma once
#include <vector>
#include <stack>
#include <cstddef>
#include <cstdint>

// Iterative DFS using an explicit stack.
// Works exactly like the original recursive implementation.
inline void dfs_iter(const std::vector<int>& A, int start,
                     std::size_t N, std::vector<uint8_t>& vis)
{
    std::stack<int> st;
    st.push(start);
    while (!st.empty())
    {
        int u = st.top();
        st.pop();
        if (vis[u])
            continue;
        vis[u] = 1;

        // Scan the row for neighbors
        const std::size_t base = static_cast<std::size_t>(u) * N;
        for (std::size_t v = 0; v < N; ++v)
        {
            if (A[base + v] == 1 && !vis[v])
                st.push(static_cast<int>(v));
        }
    }
}

/* Count the number of connected components in the undirected graph defined
 * by the adjacency matrix A.  A is stored in row-major order.
 */
int componentCount(const std::vector<int>& A, std::size_t N)
{
    // Use a byte per node – cheaper than bool on some platforms.
    std::vector<uint8_t> visited(N, 0);
    int count = 0;

    for (int i = 0; i < static_cast<int>(N); ++i)
    {
        if (!visited[i])
        {
            dfs_iter(A, i, N, visited);
            ++count;
        }
    }
    return count;
}
