/*
 * Compute the maximum node degree in an undirected graph described by an
 * adjacency matrix stored in row-major order.
 *
 * Parameters
 * ----------
 * A   : adjacency matrix, flattened 1D vector of size N*N
 * N   : number of nodes
 *
 * Returns
 * -------
 *   The highest degree among all nodes.
 *   The function preserves the exact semantics of the original implementation.
 */
int maxDegree(std::vector<int> const& A, size_t N) {
    int highestDegree = 0;

    // Parallel reduction over rows. Each thread calculates the degree for
    // a subset of rows, then the maximum is combined at the end.
#pragma omp parallel for reduction(max : highestDegree) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        int degree = 0;
        const int* row_start = A.data() + i * N;
        // Unroll the inner loop for a small speed improvement on small N.
        for (size_t j = 0; j < N; j += 8) {
            degree += row_start[j];
            if (j + 1 < N) degree += row_start[j + 1];
            if (j + 2 < N) degree += row_start[j + 2];
            if (j + 3 < N) degree += row_start[j + 3];
            if (j + 4 < N) degree += row_start[j + 4];
            if (j + 5 < N) degree += row_start[j + 5];
            if (j + 6 < N) degree += row_start[j + 6];
            if (j + 7 < N) degree += row_start[j + 7];
        }
        highestDegree = std::max(highestDegree, degree);
    }

    return highestDegree;
}
