struct Element {
    size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the pre‑allocated vector `z`.
 *
 * The implementation runs two parallel loops – one for `x`, one for `y`.
 * Each write to `z` is protected by an atomic operation to avoid data races.
 *
 * Example:
 *   input: x=[{5,12},{8,3},{12,-1}], y=[{3,1},{5,-2},{7,1},{8,-3}], alpha=1
 *   output: z=[{3,1},{5,10},{7,1},{12,-1}]
 */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
    /* Update contributions from the first vector (scaled by alpha) */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        const auto &e = x[i];
        double val = alpha * e.value;
#pragma omp atomic
        z[e.index] += val;
    }

    /* Update contributions from the second vector (unscaled) */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        const auto &e = y[i];
        double val = e.value;
#pragma omp atomic
        z[e.index] += val;
    }
}
