/*
   Count the number of cartesian points in each quadrant.
   The vector `points` contains a list of `Point` objects.
   Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9}, {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins) {
    // Initialise the output bins to zero (in case the caller never zeroes them)
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const size_t n = points.size();
    if (n == 0) return;

    // Parallel reduction using a private local array for each thread
    #pragma omp parallel
    {
        // Each thread keeps its own partial counts
        size_t local[4] = {0, 0, 0, 0};

        #pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i) {
            const auto& p = points[i];
            if (p.x >= 0.0) {
                if (p.y >= 0.0) ++local[0];
                else           ++local[3];
            } else {
                if (p.y >= 0.0) ++local[1];
                else           ++local[2];
            }
        }

        // Merge the local counts into the global result
        #pragma omp atomic
        bins[0] += local[0];
        #pragma omp atomic
        bins[1] += local[1];
        #pragma omp atomic
        bins[2] += local[2];
        #pragma omp atomic
        bins[3] += local[3];
    }
}
