#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <limits>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Compute y = alpha*A*x + beta*y where
 *   alpha, beta – scalars
 *   x, y       – vectors (length N)
 *   A          – sparse matrix in COO format (size M x N)
 *
 * The function preserves the exact semantics of the reference
 * implementation while employing OpenMP parallelism and a few
 * micro‑optimisations.
 */
void spmv(double alpha,
          std::vector<COOElement> const& A,
          std::vector<double> const& x,
          double beta,
          std::vector<double> & y,
          std::size_t M,
          std::size_t N)
{
    /* ---- 1. scale y by beta --------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    /* ---- 2. accumulate alpha*A*x into y --------------------------------- */
    /* We use atomic updates because different elements may share the same
     * target row.  The size of A is usually much larger than M, so the
     * cost of the atomic operation is negligible compared to the
     * memory traffic.  For very sparse matrices the branch
     * (row/column < M/N) dominates and is kept unchanged to preserve
     * behaviour. */
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < A.size(); ++k) {
        const auto &e = A[k];
        if (e.row < M && e.column < N) {
            double prod = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += prod;
        }
    }
}
