/* Count the number of doubles in the vector x that have a fractional part 
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in `bins`.
   Examples:
   input: [7.8, 4.2, 9.1, 7.6, 0.27, 1.5, 3.8]
   output: [2, 1, 2, 2]
   input: [1.9, 0.2, 0.6, 10.1, 7.4]
   output: [2, 1, 1, 1]
*/
void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins) {
    constexpr double q1 = 0.25, q2 = 0.5, q3 = 0.75;
    // initialize array for reduction
    std::array<std::size_t, 4> local = {0,0,0,0};

    #pragma omp parallel for reduction(+:local[:4]) schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        const double val = x[i];
        const int int_part = static_cast<int>(val);          // truncates toward zero
        const double frac = val - static_cast<double>(int_part);
        if (frac < q1)           local[0] += 1;
        else if (frac < q2)      local[1] += 1;
