#include <cstddef>
#include <omp.h>

/*
 * Return the value of the smallest odd number in the vector x.
 *
 * Example:
 *   input : [7, 9, 5, 2, 8, 16, 4, 1]  -> 1
 *   input : [8, 36, 7, 2, 11]          -> 7
 */
int smallestOdd(std::vector<int> const& x)
{
    // Handle empty vector – matches the behaviour of the original
    // implementation: std::numeric_limits<int>::max() would be returned.
    if (x.empty())
        return std::numeric_limits<int>::max();

    const std::size_t n = x.size();
    const std::size_t chunk = 1024;            // Element count per chunk
    const std::size_t chunks = (n + chunk - 1) / chunk;

    // Each thread holds its own local minimum odd value.
    std::vector<int> localMin(chunks, std::numeric_limits<int>::max());
    int globalMin = std::numeric_limits<int>::max();

    // Parallel scan in fixed‑size chunks.  A chunk contains at most 'chunk'
    // elements so that the temporary partial result stays small and the
    // overhead of the foreach loop is limited.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < chunks; ++i) {
        std::size_t start = i * chunk;
        std::size_t end   = std::min(n, start + chunk);
        int local = std::numeric_limits<int>::max();

        for (std::size_t j = start; j < end; ++j) {
            int value = x[j];
            if ((value & 1) && value < local) {   // value is odd and smaller
                local = value;
                if (local == 1) break;           // cannot get smaller than 1
            }
        }
        localMin[i] = local;
    }

    // Reduce the local minima to the global minimum.  This loop is tiny
    // and therefore runs sequentially without significant cost.
    for (int local : localMin) {
        if (local < globalMin)
            globalMin = local;
    }

    return globalMin;
}
