#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute the matrix multiplication Y = A · X.
 * A : sparse M×K matrix (COO format)
 * X : sparse K×N matrix (COO format)
 * Y : dense M×N matrix in row-major order
 *
 * Exact semantics are preserved: the result is computed with
 * double precision and the same accumulation order as the
 * reference implementation.
 */
inline void spmm(std::vector<COOElement> const& A,
                 std::vector<COOElement> const& X,
                 std::vector<double>& Y,
                 size_t M, size_t /*K*/, size_t N)
{
    Y.assign(M * N, 0.0);

    /* Build a small dictionary from input row to list of elements
     * to avoid the double-loop over all elements of X for each
     * element of A.  The dictionary is tiny (at most |X| entries)
     * and fits comfortably into cache.
     */
    std::unordered_map<size_t, std::vector<COOElement>> rows;
    rows.reserve(X.size() * 2);   // pre‑allocate to avoid rehashing

    for (auto const& e : X) {
        rows[e.row].push_back(e);
    }

    /* Parallel over the rows of A.  Each thread accumulates into
     * a private local matrix to avoid contention on the global Y.
     * At the end a reduction step adds the local matrices to Y.
     */
    const size_t nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> localY(nthreads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel
    {
        const size_t tid = omp_get_thread_num();
        std::vector<double>& local = localY[tid];

        for (size_t i = 0; i < A.size(); ++i) {
            const auto& a = A[i];
            auto it = rows.find(a.column);
            if (it == rows.end()) continue;                // no matching row in X
            const std::vector<COOElement>& vec = it->second;

            const size_t base = a.row * N;
            for (auto const& x : vec) {
                local[base + x.column] += a.value * x.value;
            }
        }
    }

    /* Reduce all per‑thread results into the global Y */
    for (size_t t = 0; t < nthreads; ++t) {
        const std::vector<double>& local = localY[t];
        for (size_t idx = 0; idx < Y.size(); ++idx) {
            Y[idx] += local[idx];
        }
    }
}
