/* Return the Euclidean distance between the closest two points in 'points'.
   The implementation uses a parallel O(n²) brute‑force search with a
   squared‑distance comparison to avoid the expensive sqrt in the inner
   loop.  The final distance is returned after taking the square root.  */
static inline double closestPair(const std::vector<Point> &points)
{
    const size_t n = points.size();
    if (n < 2) return 0.0;

    double minDistSq = std::numeric_limits<double>::max();

    /* Parallelise the outer loop (OpenMP default shared) with a reduction
       over the minimum squared distance.                                                   */
    #pragma omp parallel for schedule(static, 64) reduction(min:minDistSq)
    for (size_t i = 0; i + 1 < n; ++i) {
        const Point &pi = points[i];
        for (size_t j = i + 1; j < n; ++j) {
            const Point &pj = points[j];
            const double dx  = pj.x - pi.x;
            const double dy  = pj.y - pi.y;
            const double dSq = dx * dx + dy * dy;
            if (dSq < minDistSq) minDistSq = dSq;
        }
    }

    return std::sqrt(minDistSq);
