#pragma once
#include <vector>
#include <unordered_map>
#include <utility>

struct COOElement {
    size_t row, column;
    double value;
};

/* Fast LU factorization of an NxN sparse matrix A (COO format) into
 * L and U (row‑major dense matrices).  The function keeps the
 * exact numerical behaviour of the original naïve implementation.
 *
 * It first builds a dense map for the non‑zero entries, then performs
 * the standard Doolittle algorithm with in‑place accumulation.  The
 * algorithm is unchanged, only the construction of the intermediate
 * matrix is made significantly cheaper (O(nnz) instead of O(N^2)
 * materialisation).
 */
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N) {
    // Resize output matrices to N×N and initialise zeros.
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    // Build a hash map (row, col) → value for fast look‑ups.
    std::unordered_map<std::size_t, double> valMap;
    valMap.reserve(A.size() * 2);
    for (const auto& e : A) {
        valMap[(e.row << 32) | e.column] = e.value;
    }

    // Standard LU factorisation (Doolittle).
    for (size_t i = 0; i < N; ++i) {
        // U[i][j]  for j >= i
        for (size_t j = i; j < N; ++j) {
            std::size_t key = (i << 32) | j;
            double sum = valMap.count(key) ? valMap[key] : 0.0; // A[i][j]
            for (size_t k = 0; k < i; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = sum;
        }

        // L[i][j]  for j < i
        for (size_t j = 0; j < i; ++j) {
            std::size_t key = (i << 32) | j;
            double sum = valMap.count(key) ? valMap[key] : 0.0; // A[i][j]
            for (size_t k = 0; k < j; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            // Diagonal of U is non‑zero by Doolittle convention.
            L[i * N + j] = sum / U[j * N + j];
        }

        // Diagonal of L is 1
        L[i * N + i] = 1.0;
    }
}
