#include <cstddef>

/* Return the number of vertices in the largest component of the graph defined
   by the adjacency matrix A (row‑major format).  The function is
   functional‑equivalent to the original but avoids recursion and
   performs the component traversal iteratively for better cache
   locality and lower overhead. */
int largestComponent(const std::vector<int> &A, size_t N) {
    // use unsigned char to keep the visited array compact
    std::vector<unsigned char> visited(N, 0);
    int maxCount = 0;
    std::vector<int> stack;
    stack.reserve(N);

    for (size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        int count = 0;
        stack.clear();
        stack.push_back(static_cast<int>(start));
        visited[start] = 1;

        while (!stack.empty()) {
            int u = stack.back();
            stack.pop_back();
            ++count;

            const int *row = &A[u * N];
            for (size_t v = 0; v < N; ++v) {
                if (row[v] && !visited[v]) {
                    visited[v] = 1;
                    stack.push_back(static_cast<int>(v));
                }
            }
        }

        if (count > maxCount) maxCount = count;
    }

    return maxCount;
}
