// Simple point structure
struct Point
{
    double x, y;
};

// Compute area of triangle ABC using cross product (no abs, handled later)
inline double triArea(const Point& a, const Point& b, const Point& c)
{
    // (b-a) x (c-a) = (b.x-a.x)*(c.y-a.y) - (b.y-a.y)*(c.x-a.x)
    return 0.5 * std::abs((b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x));
}

// Return the area of the smallest triangle that can be formed by any 3 points
inline double smallestArea(const std::vector<Point>& points)
{
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelizing the outer two loops. The innermost loop remains sequential
    // to keep the reduction logic simple and cache‑friendly.
    #pragma omp parallel for collapse(2) schedule(static) reduction(min:minArea)
    for (size_t i = 0; i < n - 2; ++i)
    {
        for (size_t j = i + 1; j < n - 1; ++j)
        {
            const Point& A = points[i];
            const Point& B = points[j];
            for (size_t k = j + 1; k < n; ++k)
            {
                const double area = triArea(A, B, points[k]);
                if (area < minArea)
                    minArea = area;
            }
        }
    }

    return minArea;
}
