struct Point
{
    double x, y;
};

/*  Convex hull – O(n log n) (Monotone chain).
 *  Exact same semantics as the reference implementation.
 */
inline double cross(const Point *a, const Point *b, const Point *c) noexcept
{
    return (b->x - a->x) * (c->y - a->y) - (b->y - a->y) * (c->x - a->x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull)
{
    const size_t n = points.size();
    if (n < 3)
    {
        hull = points;
        return;
    }

    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point &a, const Point &b)
              {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    hull.resize(2 * n);
    size_t k = 0;

    /* lower hull */
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 &&
               cross(&hull[k - 2], &hull[k - 1], &sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    /* upper hull */
    for (size_t i = n - 1, t = k + 1; i > 0; --i)
    {
        while (k >= t &&
               cross(&hull[k - 2], &hull[k - 1], &sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }

    hull.resize(k - 1);
}
