#include <algorithm>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the input vector `x` into `output`.
 * Exact semantics are identical to std::inclusive_scan (inclusion of the
 * current element at each step).
 *
 * Parameters
 * ----------
 * x      : input data (const reference)
 * output : result buffer; must be pre-sized to x.size()
 */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    const std::size_t n = x.size();
    if (n == 0) return;

    /* If the data is too small, fall back to the serial implementation
     * to avoid the thread‑creation overhead. */
    if (n < 1024) {
        std::partial_sum(x.begin(), x.end(), output.begin());
        return;
    }

    /* Number of threads that will be used.  OpenMP will pick the optimal
     * number but we clamp it to 8 as specified in the environment. */
    int threads = std::max(1, std::min(8, static_cast<int>(omp_get_max_threads())));

    /* Split the data into `threads` contiguous blocks.  Each block will be
     * processed independently in parallel.  We keep an auxiliary vector
     * containing the personal block sums (the last element of each block). */
    std::vector<int64_t> block_sums(threads);
    std::size_t block_size = (n + threads - 1) / threads;   // ceil

    /* ---------- 1. Compute inclusive scan of each block in parallel ---------- */
#pragma omp parallel num_threads(threads)
    {
        int tid = omp_get_thread_num();
        std::size_t start = tid * block_size;
        std::size_t end   = std::min(start + block_size, n);

        if (start >= end) return;  // empty block

        std::partial_sum(x.begin() + start, x.begin() + end, output.begin() + start);

        /* Store the sum of this block (last element of the block's output) */
        block_sums[tid] = output[end - 1];
    }

    /* ---------- 2. Accumulate block_sums to obtain offsets for each block ---------- */
    /* The offset for block i is the sum of all previous block sums. */
    std::vector<int64_t> offsets(threads, 0);
    for (int i = 1; i < threads; ++i) {
        offsets[i] = offsets[i - 1] + block_sums[i - 1];
    }

    /* ---------- 3. Add the offset to each block (except the first) ---------- */
#pragma omp parallel for num_threads(threads)
    for (int i = 1; i < threads; ++i) {
        std::size_t start = i * block_size;
        std::size_t end   = std::min(start + block_size, n);
        if (start >= end) continue;
        int64_t offset = offsets[i];
        for (std::size_t j = start; j < end; ++j) {
            output[j] += offset;
        }
    }
}
