#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete fourier transform of vector x.
 * The result is stored in output. The algorithm remains O(N²)
 * but is heavily vectorised and parallelised for maximum speed.
 */
inline void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output.resize(N);

    // Allocate pre‑computed sin/cos table: one row per k (output index)
    std::vector<std::vector<double>> sin_cos_table(N, std::vector<double>(2 * N));
    for (std::size_t k = 0; k < N; ++k) {
        const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);
        double* ptr = sin_cos_table[k].data();
        for (std::size_t n = 0; n < N; ++n) {
            const double angle = two_pi_over_N * static_cast<double>(n) * static_cast<double>(k);
            *ptr++ = std::cos(angle);   // real part
            *ptr++ = -std::sin(angle);  // imag part (negative for e^{-jθ})
        }
    }

    // Parallel over output indices k
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < (int)N; ++k) {
        const double* cos_sin_row = sin_cos_table[k].data();
        double sum_real = 0.0;
        double sum_imag = 0.0;
        const double* x_ptr = x.data();

        // Unroll inner loop by 4 for a small vectorisation hint
        std::size_t n = 0;
        for (; n + 3 < N; n += 4) {
            double xr0 = *x_ptr++; double cr0 = *cos_sin_row++; double si0 = *cos_sin_row++;
            double xr1 = *x_ptr++; double cr1 = *cos_sin_row++; double si1 = *cos_sin_row++;
            double xr2 = *x_ptr++; double cr2 = *cos_sin_row++; double si2 = *cos_sin_row++;
            double xr3 = *x_ptr++; double cr3 = *cos_sin_row++; double si3 = *cos_sin_row++;

            sum_real += xr0 * cr0 + xr1 * cr1 + xr2 * cr2 + xr3 * cr3;
            sum_imag += xr0 * si0 + xr1 * si1 + xr2 * si2 + xr3 * si3;
        }
        for (; n < N; ++n) {
            double xr = *x_ptr++;
            double cr = *cos_sin_row++;
            double si = *cos_sin_row++;
            sum_real += xr * cr;
            sum_imag += xr * si;
        }
        output[k] = std::complex<double>(sum_real, sum_imag);
    }
}
