#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(
        const std::vector<COOElement>& A,
        const std::vector<double>&      b,
        std::vector<double>&            x,
        size_t                          N) {

    /* ---------- 1. Build a dense N×N matrix (row‑major) ---------- */
    std::vector<double> mat(n_ * n_, 0.0);                     // flat storage
    for (const auto& e : A)                                 // O(nnz)
        mat[e.row * N + e.column] = e.value;

    /* ---------- 2. Copy RHS ------------------------------------- */
    std::vector<double> rhs = b;                            // copy b

    /* ---------- 3. Gaussian elimination -------------------------- */
    for (size_t i = 0; i < N; ++i)
    {
        /* --- pivot selection ----------------------------------- */
        size_t maxRow = i;
        double maxVal = std::fabs(mat[i * N + i]);

        for (size_t r = i + 1; r < N; ++r) {
            double v = std::fabs(mat[r * N + i]);
            if (v > maxVal) {
                maxVal = v;
                maxRow = r;
            }
        }

        /* --- swap rows if needed ------------------------------- */
        if (maxRow != i) {
            for (size_t c = i; c < N; ++c) {
                std::swap(mat[maxRow * N + c], mat[i * N + c]);
            }
            std::swap(rhs[maxRow], rhs[i]);
        }

        const double pivot = mat[i * N + i];

        /* --- eliminate rows below i (parallelized) ------------- */
        #pragma omp parallel for schedule(static)
        for (size_t r = i + 1; r < N; ++r) {
            const double factor  = -mat[r * N + i] / pivot;
            mat[r * N + i] = 0.0;                       // explicit zero

            double* dst = &mat[r * N + i + 1];
            const double* src = &mat[i * N + i + 1];
            for (size_t c = i + 1; c < N; ++c, ++src, ++dst)
                *dst += factor * (*src);

            rhs[r] += factor * rhs[i];
        }
    }

    /* ---------- 4. Back‑substitution ---------------------------- */
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        const double* row = &mat[i * N];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j)
            sum -= row[j] * x[j];
        x[i] = sum / mat[i * N + i];
    }
}
