#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

/* 
 * Cooley–Tukey radix‑2 iterative FFT.
 * Requires |x| to be a power of two.
 * The result is written into r (real part) and i (imag part).
 *
 * The implementation is fully in‑place, uses a temporary array for the
 * reordered input, and parallelises the butterfly stage with OpenMP
 * for the maximum speed on an 8‑thread x86‑64 machine.
 */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r, std::vector<double> &i)
{
    const std::size_t N = x.size();
    std::vector<std::complex<double>> a(N);

    /* ---- 1) Bit‑reversal permutation ------------------------------------ */
    std::size_t m = static_cast<std::size_t>(std::log2(N));
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t rev = j;
        rev = ((rev & 0xaaaaaaaa) >> 1) | ((rev & 0x55555555) << 1);
        rev = ((rev & 0xcccccccc) >> 2) | ((rev & 0x33333333) << 2);
        rev = ((rev & 0xf0f0f0f0) >> 4) | ((rev & 0x0f0f0f0f) << 4);
        rev = ((rev & 0xff00ff00) >> 8) | ((rev & 0x00ff00ff) << 8);
        rev = (rev >> 16) | (rev << 16);
        rev >>= 32 - m;
        a[rev] = x[j];
    }

    /* ---- 2) Iterative radix‑2 butterflies -------------------------------- */
    const double PI = std::acos(-1);
    for (std::size_t s = 1; s <= m; ++s) {
        const std::size_t mlen = 1ULL << s;          // current sub‑transform size
        const std::size_t half = mlen >> 1;          // number of butterflies
        const double angle = -PI / half;
        const std::complex<double> wlen(std::cos(angle), std::sin(angle));

        // Parallelise over the group of butterflies  
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += mlen) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < half; ++j) {
                std::complex<double> t = w * a[k + j + half];
                std::complex<double> u = a[k + j];
                a[k + j] = u + t;
                a[k + j + half] = u - t;
                w *= wlen;
            }
        }
    }

    /* ---- 3) Split into real and imaginary parts -------------------------- */
    r.resize(N);
    i.resize(N);
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
