/* Compute one iteration of a 3‑point 1‑D Jacobi stencil.
   Boundary points read out‑of‑bounds values as zero.
   This implementation keeps the exact semantics while
   exploiting SIMD friendly layout and OpenMP parallelism.
*/
void jacobi1D(std::vector<double> const& input, std::vector<double>& output) {
    const std::size_t n = input.size();
    if (n == 0) return;

    const double* in  = input.data();
    double*       out = output.data();

    /* Handle the first element explicitly (no left neighbour). */
    if (n > 0) {
        out[0] = (in[0] + (n > 1 ? in[1] : 0.0)) / 3.0;
    }

    /* Interior elements: all have two neighbours. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        out[i] = (in[i - 1] + in[i] + in[i + 1]) / 3.0;
    }

    /* Handle the last element explicitly (no right neighbour). */
    if (n > 1) {
        out[n - 1] = ((n > 1 ? in[n - 2] : 0.0) + in[n - 1]) / 3.0;
    }
}
