#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstring>
#include <omp.h>

/*  Optimised radix‑2 Cooley‑Tukey FFT
 *
 *  Parallelism:
 *      • The bit‑reversal permutation and the final conjugation
 *        are embarrassingly parallelised with OpenMP.
 *      • Each FFT stage is serial because it contains data
 *        dependencies, but the cost of a stage is small.
 *
 *  Accuracy: identical to the reference implementation.
 *  Dependencies: <vector>, <complex>, <cmath>, <cstring>, <omp.h>
 */

static inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N == 0) return;

    /* ---------- Pre‑compute twiddle factors ---------- */
    const double pi  = M_PI;
    const double theta0 = pi / N;
    std::vector<std::complex<double>> W(N/2);
    for (size_t k = 0; k < N/2; ++k)
        W[k] = std::polar(1.0, -theta0 * k);          // exp(-j*2πk/N)

    /* ---------- Bit‑reversal permutation ---------- */
    const size_t logN = static_cast<size_t>(std::log2(N));
    const size_t revMask = (1u << logN) - 1;
#pragma omp parallel for
    for (size_t i = 0; i < N; ++i) {
        size_t j = i, r = 0;
        for (size_t b = 0; b < logN; ++b) {
            r = (r << 1) | (j & 1);
            j >>= 1;
        }
        if (r > i) std::swap(x[i], x[r]);
    }

    /* ---------- Main FFT stages ---------- */
    for (size_t s = 1; s <= logN; ++s) {
        const size_t m = 1u << s;          // size of sub‑FFT
        const size_t half = m >> 1;        // butterfly half‑size
        const size_t step = N / m;         // twiddle stride

        for (size_t k = 0; k < half; ++k) {
            const std::complex<double> w = W[k * step];
#pragma omp parallel for schedule(static)
            for (size_t j = k; j < N; j += m) {
                const size_t l = j + half;
                std::complex<double> t = x[l] * w;
                x[l] = x[j] - t;
                x[j] += t;
            }
        }
    }

    /* ---------- Conjugate all elements ---------- */
#pragma omp parallel for
    for (size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
