#pragma once
#include <vector>
#include <omp.h>
#include <cstddef>

/*
 * Parallel blocked matrix‑vector multiplication.
 * 
 * Parameters:
 *   - A: M×N matrix in row‑major order (size = M*N)
 *   - x: vector of length N
 *   - y: output vector of length M (must be pre‑allocated)
 *   - M, N: matrix dimensions
 */
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 std::size_t M,
                 std::size_t N)
{
    const double *Aptr = A.data();
    const double *xptr = x.data();
          double *yptr = y.data();

    /* Choose a block size that keeps inner loops in L2/L3 cache.
     * 32 elements ≈ 256 bytes – fits comfortably in typical cache lines. */
    constexpr std::size_t BLOCK = 32;

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        const double *rowA = Aptr + i * N;
        double sum = 0.0;

        /* Process columns in blocks to enhance spatial locality. */
        std::size_t j = 0;
        for (; j + BLOCK <= N; j += BLOCK) {
            /* Unroll the inner loop by a factor of 4 for extra speed. */
            for (std::size_t k = 0; k < BLOCK; k += 4) {
                sum += rowA[j + k    ] * xptr[j + k    ];
                sum += rowA[j + k + 1] * xptr[j + k + 1];
                sum += rowA[j + k + 2] * xptr[j + k + 2];
                sum += rowA[j + k + 3] * xptr[j + k + 3];
            }
        }

        /* Handle remaining columns that don't fit into a block. */
        for (; j < N; ++j) {
            sum += rowA[j] * xptr[j];
        }
        yptr[i] = sum;
    }
}
