#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row‑major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
*/
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M,
                 size_t K,
                 size_t N)
{
    /* Basic tiling parameters – tuned for L1/L2 cache (88‑byte cache line,
       double = 8 bytes → 11 doubles per line). */
    constexpr size_t BLOCK_M = 64;   // rows of A / C
    constexpr size_t BLOCK_K = 64;   // inner dimension
    constexpr size_t BLOCK_N = 64;   // cols of B / C

    /* Ensure C is zeroed before accumulation (required by the mathematics
       but not guaranteed by the caller). */
    std::fill(C.begin(), C.end(), 0.0);

    /* Parallelise the outermost loop (blocks of rows). */
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_M) {
        size_t i_limit = std::min(ii + BLOCK_M, M);
        for (size_t kk = 0; kk < K; kk += BLOCK_K) {
            size_t k_limit = std::min(kk + BLOCK_K, K);
            for (size_t jj = 0; jj < N; jj += BLOCK_N) {
                size_t j_limit = std::min(jj + BLOCK_N, N);

                /* --- Inner kernel: unrolled and cache‑friendly --- */
                for (size_t i = ii; i < i_limit; ++i) {
                    const double* A_row = &A[i * K];
                    double*       C_row = &C[i * N];
                    for (size_t k = kk; k < k_limit; ++k) {
                        double a_val = A_row[k];
                        const double* B_row = &B[k * N];
                        for (size_t j = jj; j < j_limit; ++j) {
                            C_row[j] += a_val * B_row[j];
                        }
                    }
                }
            }
        }
    }
}
