#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point { double x, y; };

inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

// Monotone chain convex hull (O(n log n)). Computes perimeter only, not hull.
double convexHullPerimeter(const std::vector<Point>& points)
{
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort points lexicographically by (x, y)
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Build lower hull
    std::vector<Point> hull;
    hull.reserve(2 * n);
    for (size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), pts[i]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // Build upper hull
    size_t t = hull.size() + 1;
    for (size_t i = n - 1; i > 0; --i) {
        while (hull.size() >= t &&
               cross(hull[hull.size() - 2], hull.back(), pts[i - 1]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i - 1]);
    }

    // Last point is same as first; remove duplicate
    hull.pop_back();

    // Compute perimeter
    double perimeter = 0.0;
    const size_t m = hull.size();
    for (size_t i = 0; i < m; ++i) {
        perimeter += dist(hull[i], hull[(i + 1) % m]);
    }

    return perimeter;
}
