```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 5‑point 2‑D Jacobi stencil.
   The function is fully parallelised with OpenMP and reduces
   branch mis‑prediction by treating the boundary cells
   separately from the interior. */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              size_t N)
{
    const double div5 = 0.2;               // 1/5

    /* First and last rows – no vertical neighbours. */
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        // top row
        output[j] = (input[j]
                      + ((j > 0)     ? input[j-1] : 0)
                      + ((j+1 < N)   ? input[j+1] : 0))
                    * div5;

        // bottom row
        size_t idx_bot = (N-1)*N + j;
        output[idx_bot] = (input[idx_bot]
                           + ((j > 0)     ? input[idx_bot-1] : 0)
                           + ((j+1 < N)   ? input[idx_bot+1] : 0))
                         * div5;
    }

    /* First and last columns of the interior rows. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i < N-1; ++i) {
        size_t idx_left = i*N;
        size_t idx_right = idx_left + N-1;

        output[idx_left] = (input[idx_left]
                            + input[idx_left - N]   // north
                            + input[idx_left + N]   // south
                            + ((i > 0)     ? 0 : 0) // west (zero)
                            + ((i+1 < N)   ? input[idx_left+1] : 0))
                          * div5;

        output[idx_right] = (input[idx_right]
                             + input[idx_right - N]   // north
                             + input[idx_right + N]   // south
                             + ((i > 0)     ? input[idx_right-1] : 0)
                             + ((i+1 < N)   ? 0 : 0))   // east (zero)
                           * div5;
    }

    /* Interior cells – full 5‑point stencil. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 1; i < N-1; ++i) {
        for (size_t j = 1; j < N-1; ++j) {
            size_t idx = i*N + j;
            output[idx] = (input[idx]
                           + input[idx - N]   // north
                           + input[idx + N]   // south
                           + input[idx - 1]   // west
                           + input[idx + 1])  // east
                          * div5;
        }
    }
}
