#include <omp.h>

static constexpr int8_t edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/**
 * Convolve a 3×3 edge detection kernel with a square grayscale image.
 *
 * imageIn  – source image (row‑major, N×N)
 * imageOut – destination image (row‑major, N×N)
 * N       – image dimension
 *
 * The function uses tile‑based 8‑bit arithmetic, bounds checking is
 * avoided by processing an outer ring on a separate loop and the core
 * kernel is executed with full OpenMP parallelism.
 */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    const int stride = static_cast<int>(N);
    const int outer = static_cast<int>(N) - 2;          // interior size
    const int outerN = outer;

    // Handle the trivial cases directly.
    if (N <= 2) {
        std::fill(imageOut.begin(), imageOut.end(), 0);
        return;
    }

    // Process the interior with minimal boundary checks.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 1; i < outerN + 1; ++i) {
        const int base = i * stride + 1;
        int *rowOut = &imageOut[base];

        const int *rowPrev  = &imageIn[(i - 1) * stride];
        const int *rowCurr  = &imageIn[i * stride];
        const int *rowNext  = &imageIn[(i + 1) * stride];

        for (int j = 1; j < outerN + 1; ++j, ++rowOut) {
            // Because the kernel is symmetric, we can compute directly.
            int sum = 8 * rowCurr[j]
                      - rowPrev[j - 1] - rowPrev[j] - rowPrev[j + 1]
                      - rowCurr[j - 1]               - rowCurr[j + 1]
                      - rowNext[j - 1] - rowNext[j] - rowNext[j + 1];

            // Clamp to [0,255]
            *rowOut = static_cast<int>(std::min(std::max(sum, 0), 255));
        }
    }

    // Top and bottom rows (first and last).
    for (int j = 0; j < static_cast<int>(N); ++j) {
        imageOut[j] = 0;
        imageOut[(N - 1) * stride + j] = 0;
    }

    // Leftmost and rightmost columns (except corners already set).
    for (int i = 1; i < static_cast<int>(N) - 1; ++i) {
        imageOut[i * stride]     = 0;
        imageOut[i * stride + N - 1] = 0;
    }
}
