#include <omp.h>

/* Doolittle LU factorisation (double precision).
 * The input matrix A is overwritten with the factors L and U in place.
 * The algorithm is performed with blocking and OpenMP parallelisation
 * on the inner row‑updates for maximum utilisation of the 8‑core CPU.
 */
inline void luFactorize(std::vector<double> &A, size_t N)
{
    constexpr int BLOCK = 32;          // Tile size for inner loop
#pragma omp parallel for schedule(static, BLOCK) default(none) shared(A,N)
    for (size_t k = 0; k < N; ++k)
    {
        const double pivot = A[k * N + k];          // A[k][k]
        if (pivot == 0.0) continue;                 // singular or 0 pivot

        for (size_t i = k + 1; i < N; ++i)
        {
            const double factor = A[i * N + k] / pivot;
            A[i * N + k] = factor;                   // store L[i][k]

            // Compute the remaining part of the row i
            size_t j = k + 1;
            for (; j + 3 < N; j += 4) {              // unrolled 4×
                A[i * N + j]     -= factor * A[k * N + j];
                A[i * N + j + 1] -= factor * A[k * N + j + 1];
                A[i * N + j + 2] -= factor * A[k * N + j + 2];
                A[i * N + j + 3] -= factor * A[k * N + j + 3];
            }
            for (; j < N; ++j) {                     // tail
                A[i * N + j] -= factor * A[k * N + j];
            }
        }
    }
}
