#pragma once
#include <vector>
#include <omp.h>

/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix in row‑major order.  b and x are 1‑D vectors of size N.
 * The function replaces the contents of `x` with the solution.
 *
 * The implementation follows a classic Gaussian elimination with partial
 * pivoting disabled (exactly the behaviour of the original code).
 * The elimination step is parallelised over the inner row loop using
 * OpenMP.  The back‑substitution step remains sequential because each
 * variable depends on the next ones.
 */
void solveLinearSystem(const std::vector<double> &A,
                       const std::vector<double> &b,
                       std::vector<double>     &x,
                       size_t                   N) {
    // Work on copies – required because the algorithm modifies the matrix.
    std::vector<double> A_copy = A;
    std::vector<double> b_copy(b);

    const size_t stride = N;                 // row stride in the 1‑D storage

    // Forward elimination
    for (size_t i = 0; i + 1 < N; ++i) {
        const double pivot = A_copy[i * stride + i];
        if (pivot == 0.0) return;          // singular matrix – behaviour from original

#pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            const double factor = A_copy[j * stride + i] / pivot;
            double *row_j = &A_copy[j * stride];
            const double *row_i = &A_copy[i * stride];
            for (size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution – sequential to preserve exact results.
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double *row_i = &A_copy[i * stride];
        for (size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / row_i[i];
    }
}
