#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// Return true if the vector x contains the value `target`.  The implementation
/// is fully equivalent to the standard `std::find` logic but is tuned for
/// performance on an 8‑thread x86‑64 system compiled with `-O2 -fopenmp`.
/// It processes the vector in parallel chunks and short‑circuits as soon
/// as the target is found.
///
/// The function is intentionally written in a way that allows the compiler
/// to vectorize the per‑chunk checks: every iteration performs a straight
/// comparison, reads the value once, and records a hit in a thread‑local
/// flag that is then collapsed with an atomic OR.
///
/// Note that the overhead of launching a parallel task for tiny vectors
/// is higher than a simple linear scan, so the implementation falls back
/// to the sequential scan for vectors smaller than a threshold.
///
inline bool contains(const std::vector<int>& x, int target) {
    const std::size_t n = x.size();

    /* Threshold below which sequential search is cheaper. */
    constexpr std::size_t SEQUENTIAL_THRESHOLD = 64;

    if (n < SEQUENTIAL_THRESHOLD) {
        for (std::size_t i = 0; i < n; ++i)
            if (x[i] == target)
                return true;
        return false;
    }

    /* Thread‑local found flag. We initialise it to false and let each
       thread set it to true when the target is observed. The master
       thread then checks the flags after the parallel region. */
    bool found = false;

    #pragma omp parallel for shared(found) lastprivate(found) schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        /* Early exit if another thread has already found the target. */
        if (found) continue;

        if (x[static_cast<std::size_t>(i)] == target) {
            found = true;               // thread‑local write
        }
    }

    return found;
}
