#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <cstring>
#include <omp.h>

/* ------------------------------------------------------------------
   Simulate one generation of Conway's Game of Life on an N×N grid.
   The input array contains 0 (dead) or 1 (alive) values, stored in
   row‑major order. The output array is written with the next state.
   ------------------------------------------------------------------ */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int>&          output,
                       size_t                     N)
{
    // Ensure the output buffer is at least N×N.
    if (output.size() < N * N)
        output.resize(N * N);

    // The kernels let us compute the neighbour sum without
    // many branch mispredictions.  We separate the two loops:
    //   1) Compute the neighbour sums into a temporary array.
    //   2) Update each cell based on its current state and sum.
    // A small second array keeps the sums, eliminating
    // redundant index math in the hot loop.
    std::vector<uint8_t> neighSum(N * N);

    const int *in = input.data();
    uint8_t *sum = neighSum.data();

#pragma omp parallel
    {
#pragma omp for schedule(static)
        for (size_t idx = 0; idx < N * N; ++idx)
        {
            size_t i = idx / N;
            size_t j = idx - i * N;

            uint8_t s = 0;
            // Four direct neighbours
            if (i > 0)     s += in[(i - 1) * N + j];
            if (i + 1 < N) s += in[(i + 1) * N + j];
            if (j > 0)     s += in[i * N + j - 1];
            if (j + 1 < N) s += in[i * N + j + 1];
            // Four diagonal neighbours
            if (i > 0 && j > 0)              s += in[(i - 1) * N + j - 1];
            if (i > 0 && j + 1 < N)           s += in[(i - 1) * N + j + 1];
            if (i + 1 < N && j > 0)           s += in[(i + 1) * N + j - 1];
            if (i + 1 < N && j + 1 < N)       s += in[(i + 1) * N + j + 1];

            sum[idx] = s;
        }

#pragma omp for schedule(static)
        for (size_t idx = 0; idx < N * N; ++idx)
        {
            uint8_t s  = sum[idx];
            uint8_t cur = static_cast<uint8_t>(in[idx]);

            // Apply the Game of Life rules using a compact expression.
            // A live cell survives if it has 2 or 3 neighbours.
            // A dead cell becomes alive if it has exactly 3 neighbours.
            // All other cases result in death (or staying dead).
            uint8_t next = (cur & ((s == 2) | (s == 3))) | (!cur & (s == 3));
            output[idx] = static_cast<int>(next);
        }
    }
}
