#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstring>
#include <omp.h>

// Forward declaration for utility functions
static inline void bitReverseArray(std::complex<double>* a, unsigned int n, unsigned int log2n);
static inline void gatherTwiddles(std::complex<double>* twiddles, unsigned int n);

// ------------------------------------------------------------------
// In‑place radix‑2 Cooley–Tukey FFT (iterative, bit‑reversal order)
// ---------------------------------------------------------------
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>> &output)
{
    // Prepare output (copy of input)
    output = x;
    const unsigned int N = output.size();
    if (N <= 1) return;                           // Trivial case

    // ---------- Bit‑reversal permutation ----------
    // Compute log2(N) once
    const unsigned int log2n = static_cast<unsigned int>(std::log2(N));

    // Prepare storage for data as array for efficient indexing
    std::vector<std::complex<double>> &data = output;
    bitReverseArray(data.data(), N, log2n);

    // ---------- Compute twiddle factors ----------
    std::vector<std::complex<double>> twiddles(N/2);
    gatherTwiddles(twiddles.data(), N);

    // ---------- Butterfly stages ----------
    // Each stage doubles the butterfly size
    unsigned int half = 1;
    const unsigned int maxStage = log2n;
    for (unsigned int stage = 0; stage < maxStage; ++stage, half <<= 1) {
        const unsigned int step = half << 1;           // 2*half
        const unsigned int stride = N / step;

        // Parallelise over *block* pairs (each block contains `step` points)
        #pragma omp parallel for schedule(static)
        for (unsigned int block = 0; block < half; ++block) {
            const unsigned int indexBase = block * step;
            const unsigned int twiddleIndex = block * stride;

            for (unsigned int j = 0; j < half; ++j) {
                const unsigned int i = indexBase + j;
                const unsigned int k = i + half;

                // Butterfly
                std::complex<double> tmp = data[i] - data[k];
                data[i] += data[k];
                data[k] = tmp * twiddles[twiddleIndex + j];
            }
        }
    }
}

//// ----------------------------------------------------------------------
//// Helper: bit‑reverse permutation
//// ----------------------------------------------------------------------
static inline void bitReverseArray(std::complex<double>* a, unsigned int n, unsigned int log2n)
{
    for (unsigned int i = 0; i < n; ++i) {
        unsigned int j = i;
        j = ((j & 0x55555555u) << 1) | ((j & 0xaaaaaaaau) >> 1);
        j = ((j & 0x33333333u) << 2) | ((j & 0xccccccccu) >> 2);
        j = ((j & 0x0f0f0f0fu) << 4) | ((j & 0xf0f0f0f0u) >> 4);
        j = ((j & 0x00ff00ffu) << 8) | ((j & 0xff00ff00u) >> 8);
        j = (j << 16) | (j >> 16);
        j >>= (32 - log2n);
        if (j > i) {
            std::complex<double> tmp = a[i];
            a[i] = a[j];
            a[j] = tmp;
        }
    }
}

//// ----------------------------------------------------------------------
//// Helper: compute twiddle factors e^(-2πi k / N) for k = 0..N/2-1
//// ----------------------------------------------------------------------
static inline void gatherTwiddles(std::complex<double>* twiddles, unsigned int N)
{
    const double twoPi = -2.0 * M_PI;
    for (unsigned int k = 0; k < N/2; ++k) {
        double angle = twoPi * k / static_cast<double>(N);
        twiddles[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }
}
