#pragma once
#include <vector>
#include <cmath>
#include <cstddef>
#include <cstddef>
#include <limits>
#include <omp.h>

#if !defined(M_PI)
    #define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// Helper struct used in the OpenMP custom reduction.
// -----------------------------------------------------------------------------
struct MinState {
    double  min_val;
    std::size_t min_idx;
};

// Custom reduction definition for OpenMP 4.5+
// Combines two MinState objects by keeping the one with the smaller
// min_val (i.e. the closer distance to PI).  If the values are equal,
// the smaller index is kept to provide deterministic results.
#pragma omp declare reduction \
    (minState   \
        : MinState      \
        : omp_out.min_val = omp_in.min_val; \
            omp_out.min_idx = omp_in.min_idx; \
    omp_out.min_val = omp_in.min_val < omp_out.min_val ? omp_in.min_val : omp_out.min_val; \
    omp_out.min_idx = omp_in.min_val < omp_out.min_val ? omp_in.min_idx : omp_out.min_idx; \
    omp_out.min_val = omp_in.min_val == omp_out.min_val ? \
          (omp_in.min_idx < omp_out.min_idx ? omp_in.min_idx : omp_out.min_idx) : omp_out.min_idx) \
    initializer( { std::numeric_limits<double>::infinity(), std::size_t(-1) } )

// -----------------------------------------------------------------------------
// Find the index of the element in `x` that is closest to π.
// -----------------------------------------------------------------------------
inline std::size_t findClosestToPi(const std::vector<double> &x) {
    // Handle empty vector according to the original contract (undefined behavior).
    if (x.empty()) return std::size_t(-1);

    MinState local{std::abs(x[0] - M_PI), 0};

    #pragma omp parallel for reduction(minState: local)
    for (std::size_t i = 1; i < x.size(); ++i) {
        const double d = std::abs(x[i] - M_PI);
        if (d < local.min_val) {
            local.min_val = d;
            local.min_idx = i;
        } else if (d == local.min_val && i < local.min_idx) {
            // Deterministically prefer the smaller index when distances tie.
            local.min_idx = i;
        }
    }

    return local.min_idx;
}
