#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

#ifndef M_PI
# define M_PI 3.14159265358979323846264338327950288
#endif

// -----------------------------------------------------------------------------
// Fast Cooley‑Tukey radix‑2 FFT (in‑place, double precision)
// -----------------------------------------------------------------------------
static inline void fft_radix2(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const int logN = static_cast<int>(std::log2(static_cast<double>(N)));
    if ((1U << logN) != N) throw std::runtime_error("size must be power of two");

    // Bit‑reversal permutation
    std::vector<std::uint32_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::uint32_t r = static_cast<std::uint32_t>(i);
        r = ((r & 0xaaaaaaaaU) >> 1) | ((r & 0x55555555U) << 1);
        r = ((r & 0xccccccccU) >> 2) | ((r & 0x33333333U) << 2);
        r = ((r & 0xf0f0f0f0U) >> 4) | ((r & 0x0f0f0f0fU) << 4);
        r = ((r & 0xff00ff00U) >> 8) | ((r & 0x00ff00ffU) << 8);
        r = (r >> 16) | (r << 16);
        rev[i] = r >> (32 - logN);
    }
    for (std::size_t i = 0; i < N; ++i)
        if (rev[i] > i) std::swap(x[i], x[rev[i]]);

    // Iterative FFT
    for (int s = 1; s <= logN; ++s) {
        const std::size_t m     = 1U << s;
        const std::size_t m2    = m >> 1;
        const double theta      = -M_PI / static_cast<double>(m2);
        const std::complex<double> w_m = std::complex<double>(std::cos(theta), std::sin(theta));

        // Parallel over outer loops: no data dependency between the sub‑radices
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < m2; ++k) {
            std::complex<double> w = 1.0;
            for (std::size_t j = k; j < N; j += m) {
                const std::size_t l = j + m2;
                const std::complex<double> t = w * x[l];
                x[l] = x[j] - t;
                x[j] += t;
                w *= w_m;
            }
        }
    }
}

// -----------------------------------------------------------------------------
// Forward FFT (exactly identical to the original helper)
// -----------------------------------------------------------------------------
static inline void fft_helper(std::vector<std::complex<double>>& x)
{
    fft_radix2(x);
}

// -----------------------------------------------------------------------------
// Inverse FFT
// -----------------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    // c⁎–{forward}–c⁎ / N
    std::transform(x.begin(), x.end(), x.begin(),
                   [](auto &v){ return std::conj(v); });

    fft_helper(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](auto &v){ return std::conj(v); });

    const double invN = 1.0 / static_cast<double>(x.size());
    std::transform(x.begin(), x.end(), x.begin(),
                   [invN](auto &v){ return v * invN; });
}
