#pragma once
#include <vector>
#include <cstddef>
#ifdef _OPENMP
#include <omp.h>
#endif

/* Set every cell's value to 1 if it has exactly one
 * neighbor that's a 1. Otherwise set it to 0.
 * The function maintains identical semantics to the reference
 * implementation but is heavily tuned for a modern x86-64
 * processor with OpenMP parallelism.
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     std::size_t N)
{
    // Guard against empty matrix
    if (N == 0) return;

#ifdef _OPENMP
    // Parallelise the outer loop. The inner loop is kept on the same
    // cache line for each thread to minimise false sharing.
    #pragma omp parallel for schedule(static)
#endif
    for (std::size_t i = 0; i < N; ++i) {
        // Pointers to the current row in input and output
        const int* prevRow = (i > 0)      ? input.data() + (i-1)*N : nullptr;
        const int* curRow  = input.data() + i*N;
        const int* nextRow = (i < N-1)    ? input.data() + (i+1)*N : nullptr;
        int* outRow       = output.data() + i*N;

        // Manual unrolling of the inner loop (block of 4):
        std::size_t j = 0;
        for (; j + 4 <= N; j += 4) {
            // Load neighbor values
            int t0 = (prevRow ? prevRow[j] : 0);
            int t1 = curRow[j-1];
            int t2 = curRow[j+1];
            int t3 = (nextRow ? nextRow[j] : 0);
            outRow[j] = ((t0 + t1 + t2 + t3) == 1) ? 1 : 0;

            t0 = (prevRow ? prevRow[j+1] : 0);
            t1 = curRow[j];
            t2 = curRow[j+2];
            t3 = (nextRow ? nextRow[j+1] : 0);
            outRow[j+1] = ((t0 + t1 + t2 + t3) == 1) ? 1 : 0;

            t0 = (prevRow ? prevRow[j+2] : 0);
            t1 = curRow[j+1];
            t2 = curRow[j+3];
            t3 = (nextRow ? nextRow[j+2] : 0);
            outRow[j+2] = ((t0 + t1 + t2 + t3) == 1) ? 1 : 0;

            t0 = (prevRow ? prevRow[j+3] : 0);
            t1 = curRow[j+2];
            t2 = curRow[j+4];          // safe because j+4 <= N
            t3 = (nextRow ? nextRow[j+3] : 0);
            outRow[j+3] = ((t0 + t1 + t2 + t3) == 1) ? 1 : 0;
        }

        // Handle remaining columns
        for (; j < N; ++j) {
            int cnt = 0;
            if (prevRow) cnt += prevRow[j];
            if (nextRow) cnt += nextRow[j];
            if (j > 0)    cnt += curRow[j-1];
            if (j < N-1)  cnt += curRow[j+1];
            outRow[j] = (cnt == 1) ? 1 : 0;
        }
    }
}
